INSERT OR IGNORE INTO seed_runs (id, phase_id, phase_name, batch_name, environment, status, actor, source_manifest_uri, started_at, completed_at, rows_extracted, rows_inserted, rows_updated, rows_rejected, notes, created_at, updated_at) VALUES ('seed_run_s05_political_foundation_governors_20260421', 'S05', 'Political and Electoral Foundation', 'state-governors-and-deputies', 'production', 'completed', 'replit-agent', 'docs/reports/phase-s05-political-foundation-source-manifest-2026-04-21.md', unixepoch(), unixepoch(), 36, 72, 0, 0, 'Seeded 36 state governors and 36 deputy governors from the canonical Wikipedia state-governor table after cross-validating every governor name against the official Nigeria Governors Forum public listing. No individuals fabricated. Off-cycle states each receive an explicit term row.', unixepoch(), unixepoch());
